*/
//scwin.shpco     = "Shpco";  // 선사구분자
//scwin.billDtl   = "Dtl"; // 상세구분자          
//scwin.billSearchYn = 'NO'; //BILL일자조회 구분자

scwin.certiPatternCd = "V";  // 거래명세서유형코드
scwin.fmlaClsCd      = "01"; // 서식구분코드
scwin.strPreDate = $c.date.getServerDateTime("yyyyMM")+"01";
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");// 현재일자를 구한다.

	//String 값 trim
/*
	String.prototype.trim = function() {
    	return this.replace(/(^\s*)|(\s*$)/g,"");
	}
*/

scwin.onpageload = function() {
    //공통코드 적용
    const codeOptions = [
        { grpCd: "FS500", compID: "acb_dcsnClsCd"}      //확정구분 GauceUtil.getCodeList("FS500",GauceUtil.CODE)
    ];

    $c.data.setCommonCode(codeOptions);
};

    //-------------------------------------------------------------------------
 	// 화면로딩시
	//-------------------------------------------------------------------------
	scwin.f_OnLoad = function() {

	};

    scwin.onUdcCompleted = function() {
        ed_qryConDtFm.setValue(scwin.strPreDate);
        ed_qryConDtTo.setValue(scwin.strCurDate);

		ed_bilgLodeptCd.focus();
		scwin.f_RetrieveFmalPattern();
		scwin.f_GridFmalPattern();
        acb_delYn.setValue("0");
		//f_Retrieve();

        scwin.params = $c.data.getParameter();
        // CFS 수출등록에서 호출시 조회
		if (!$c.gus.cfIsNull(scwin.params["flag"])) { 
			acb_qryConKnd.setValue("오더번호");
			ed_qryConCd.setValue(scwin.params["odrNo"]);

			scwin.f_cfsRetrieve();			
    	}
    };

  	//-------------------------------------------------------------------------
  	// 조회
	//-------------------------------------------------------------------------
	scwin.f_Retrieve = async function() {

		if(acb_qryConKnd.getValue() == "품명명" || ed_qryConCd.getValue() == ""){
		  	//validation check     
	    	if(!await $c.gus.cfValidate([ed_bilgLodeptCd,ed_qryConDtFm,ed_qryConDtTo])){
	    		return;
	    	}
		}    		 

	  	//조회시작일자가 더 클경우 체크
	  	if (!await $c.gus.cfIsAfterDate(ed_qryConDtFm.getValue(), ed_qryConDtTo.getValue())) {
 	       await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
 	       return;
    	}

        ds_merchantcertilist_con.set("certiPatternCd", scwin.certiPatternCd);
     	ds_merchantcertilist_con.set("fmlaClsCd", scwin.fmlaClsCd);

        ds_merchantcertilist_con.set("impExpDomesticClsCd01",cbx_impExpDomesticClsCd01.getValue()); //I
        ds_merchantcertilist_con.set("impExpDomesticClsCd02",cbx_impExpDomesticClsCd02.getValue()); //O
        ds_merchantcertilist_con.set("impExpDomesticClsCd03",cbx_impExpDomesticClsCd03.getValue()); //D

		if (cbx_upClsCd.getValue() != ""){
     		ds_merchantcertilist_con.set("upDownClsCd","UP");
     	} else if(cbx_downClsCd.getValue() != ""){
     		ds_merchantcertilist_con.set("upDownClsCd","DOWN");
     	} else {
     		ds_merchantcertilist_con.set("upDownClsCd","NULL");
     	}

        ds_merchantcertilist_con.set("offsetYn",cbx_offsetYn.getValue());

		//상세화면 데이타 Clear
        ds_merchantcertilist.setJSON([]);
        ds_merchantcertidtllist.setJSON([]);
        $c.sbm.execute(sbm_merchantcertilist_retrieve);

	};

    //-------------------------------------------------------------------------
  	// CFS 수출등록에서 호출시 조회
	//-------------------------------------------------------------------------
	scwin.f_cfsRetrieve = function() {
		scwin.f_Retrieve();
	};

  	//-------------------------------------------------------------------------
  	// 저장
	//-------------------------------------------------------------------------
	scwin.f_Save = async function() {
	  	if(!ds_merchantcertilist.getModifiedJSON().length != 0){
	  		await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["거래명세서"]);
        	return;        
        }	

        if(! await $c.win.confirm(MSG_CM_CRM_001))
        	return;

        $c.sbm.execute(sbm_merchantcertilist_save);

        /*
        for (var i=1; i<=ds_merchantcertilist.getRowCount(); i++) {
	        if(ds_merchantcertilist.getCellData(i, "ediSndTrgtYn") == 1){
	        	ds_merchantcertilist.getCellData(i, "ediSndClsCd") = "0";
	        	ds_merchantcertilist.getCellData(i, "ediSndDt") = "";
	        	ds_merchantcertilist.getCellData(i, "ediSndHh") = "";
	        }	
	    } */   
	};

  	//-------------------------------------------------------------------------
  	// 상세 저장
	//-------------------------------------------------------------------------
	scwin.f_SaveDtl = async function() {
	  	if(!ds_merchantcertidtllist.getModifiedJSON().length != 0){
	  		await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["거래명세서상세"]);
        	return;        
        }	

        if(!await $c.win.confirm(MSG_CM_CRM_001))
        	return;        

        for (var i=0; i<ds_merchantcertidtllist.getRowCount(); i++) {
	        if(ds_merchantcertidtllist.getCellData(i, "ediSndTrgtYn") == 1){
	        	ds_merchantcertidtllist.setCellData(i, "ediSndClsCd","0");
	        	ds_merchantcertidtllist.setCellData(i, "ediSndDt", "");
	        	ds_merchantcertidtllist.setCellData(i, "ediSndHh", "");
	        }	
	    }

        $c.sbm.execute(sbm_merchantcertidtllist_save);
	};

  	//-------------------------------------------------------------------------
  	// 전송삭제
	//-------------------------------------------------------------------------
    /*
	scwin.f_DelEdi = function() {

		if (ds_merchantcertilist.getRowCount() < 1){
		    $c.gus.cfAlertMsg("삭제전송할 데이타가 존재하지 않습니다.");
			return;			
		}

        ds_merchantcertilist.setCellData(ds_merchantcertilist.getRowPosition(), "ediSndTrgtYn","2");

        for (var i=1; i<=ds_merchantcertidtllist.getRowCount(); i++) {
	        ds_merchantcertidtllist.setCellData(i, "ediSndTrgtYn","2");
	    }

	  	if(!ds_merchantcertilist.getModifiedJSON().length != 0){
	  		$c.gus.cfAlertMsg("삭제전송된 데이타입니다.");
