        }	        	

        if(! $c.win.confirm("삭제전송 하시겠습니까?")){
			ds_merchantcertilist.undoAll();
			ds_merchantcertidtllist.undoAll();
        	return;        
        }	

        ds_merchantcertilist.setCellData(ds_merchantcertilist.getRowPosition(), "delEdiYn","Y");

        $c.sbm.execute(sbm_merchantcertilist_save);

       	//tr_merchantcertilist_save.Action = "/ds.fs.bilg.bilgrsltsmgnt.UpdateMerchantCertiCMD.do";
	    //tr_merchantcertilist_save.Post();
	};

  	//-------------------------------------------------------------------------
  	// 행삭제
	//-------------------------------------------------------------------------
	scwin.f_DelRow = function() {
        for (var i=1; i<=ds_merchantcertilist.getRowCount(); i++) {
	        if(ds_merchantcertilist.getCellData(i, "certiNo") == ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "certiNo")){

				if(ds_merchantcertilist.getCellData(i, "sellVatNo") != ""){
					$c.gus.cfAlertMsg("전표확정된 건으로 삭제할 수 없습니다.");
					return;
				}

				ds_merchantcertilist.setCellData(i, "spplyAmt"      , (ds_merchantcertilist.getCellData(i, "spplyAmt") - ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "spplyAmt")));
				ds_merchantcertilist.setCellData(i, "spplyAmtFcrc"  , (ds_merchantcertilist.getCellData(i, "spplyAmtFcrc") - ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "spply)AmtFcrc")));
				ds_merchantcertilist.setCellData(i, "vatAmt"        , (ds_merchantcertilist.getCellData(i, "vatAmt") - ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "vatAmt")));
				ds_merchantcertilist.setCellData(i, "totAmt"        , (ds_merchantcertilist.getCellData(i, "spplyAmt") + ds_merchantcertilist.getCellData(i, "vatAmt")));
	        }	
	    }   

		//ds_merchantcertidtllist.DeleteMarked();
        var row = ds_merchantcertidtllist.getRowPosition();
		ds_merchantcertidtllist.deleteRow(row);

	    var del_Status = 'true';
        for (var j=0; j<ds_merchantcertidtllist.getRowCount(); j++) {
        	if(ds_merchantcertidtllist.getRowStatus(j) != 2){
        		del_Status = 'false';
        	}	
        }

		if(del_Status == "true"){
			$c.gus.cfAlertMsg("거래명세서 전체 삭제는 불가능합니다.");
			ds_merchantcertidtllist.UndoMarked();
			return;
		}        	    

	};

  	//-------------------------------------------------------------------------
  	// 행취소
	//-------------------------------------------------------------------------
	scwin.f_CancelRow = function() {
		if(ds_merchantcertidtllist.getRowStatus(ds_merchantcertidtllist.getRowPosition()) == 2){
	        for (var i=1; i<=ds_merchantcertilist.getRowCount(); i++) {
		        if(ds_merchantcertilist.getCellData(i, "certiNo") == ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "certiNo")){
					ds_merchantcertilist.getCellData(i, "spplyAmt", ds_merchantcertilist.getCellData(i, "spplyAmt") + ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "spplyAmt"));
					ds_merchantcertilist.getCellData(i, "spplyAmtFcrc", ds_merchantcertilist.getCellData(i, "spplyAmtFcrc") + ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "spplyAmtFcrc"));
					ds_merchantcertilist.getCellData(i, "vatAmt", ds_merchantcertilist.getCellData(i, "vatAmt") + ds_merchantcertidtllist.getCellData(ds_merchantcertidtllist.getRowPosition(), "vatAmt"));								
					ds_merchantcertilist.getCellData(i, "totAmt", ds_merchantcertilist.getCellData(i, "spplyAmt") + ds_merchantcertilist.getCellData(i, "vatAmt"));
		        }	
		    }   
		}
		ds_merchantcertidtllist.UndoMarked();
	};
*/
  	//-------------------------------------------------------------------------
  	// 팝업창 처리
  	//-------------------------------------------------------------------------
	scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
	  	// 선언부
		var rtnList  = new Array();  // 공통POP-UP -> 요청화면 

		switch (disGubun) {
			case 1:
				//청구부서코드팝업			
				rtnList = udc_bilgLodeptCd.cfCommonPopUp(scwin.udc_bilgLodeptCdCallback,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);
				break;

	  		case 2:  			
				//청구처코드팝업
                //retrieveClntInfo
				rtnList = udc_bilgClntNo.cfCommonPopUp(scwin.udc_bilgClntNoCallback,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  			
				break;
	  		case 3:  		
				// 청구담당자코드 팝업			
				rtnList = udc_modId.cfCommonPopUp(scwin.udc_modIdCallback,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  				  			
				break;
            case 4:
				// 라인코드 팝업
                udc_comCodeGrid.setSelectId('retrieveLineInfo');
				rtnList = udc_comCodeGrid.cfCommonPopUp(scwin.udc_lineCdCallback,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  				  			
				break;

	  		default:
	  			break;
		}
	};

    scwin.gr_merchantcertilist_onrowindexchange = function (rowIndex, oldRow) {
console.log("gr_merchantcertilist_onrowindexchange~~~");
        var rowcnt = ds_merchantcertilist.getRowCount();
        if(rowcnt > 0){
            //scwin.f_GetDataSet("1");
            scwin.f_GetDataSet(rowIndex);
        }	
    };

    scwin.gr_merchantcertilist_oncelldblclick = async function (rowIndex, columnIndex, columnId) {
console.log("gr_merchantcertilist_oncellclick~~~");
        var rowcnt = ds_merchantcertilist.getRowCount();
        if(rowcnt > 0){
            if (columnId == "certiNo" && ds_merchantcertilist.getCellData(rowIndex, "certiNo") != ""){ 
                scwin.f_certiNoDetail();
            } else if (columnId == "slipNo" && ds_merchantcertilist.getCellData(rowIndex, "slipNo") != ""){ 
                await $c.gus.cfShowSlipInfo(ds_merchantcertilist.getCellData(rowIndex,"slipNo"));
                //scwin.f_GetDataSet(rowIndex);
            } else {
                //scwin.f_GetDataSet(rowIndex);	
            }
        }
};


	scwin.udc_bilgLodeptCdCallback = function(ret){
        scwin.f_setUdcPopCallback(ret,ed_bilgLodeptCd,ed_bilgLodeptNm);
    };

    scwin.udc_bilgClntNoCallback = function(ret){
        scwin.f_setUdcPopCallback(ret,ed_bilgClntNo,ed_bilgClntNm);
    };

	scwin.udc_lineCdCallback = function(ret){
        scwin.f_setUdcPopCallback(ret,ed_lineCd,ed_lineNm);
    };

	scwin.udc_modIdCallback = function(ret){
        scwin.f_setUdcPopCallback(ret,ed_modId,ed_modNm);
    };

//udc팝업공통 콜백처리
scwin.f_setUdcPopCallback = function(ret,objCode,objName){
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if (rtnList[0] == "N/A"){
				objCode.setValue("");
                objName.setValue("");
                objCode.hidVal = "";
				return;
			}
			objCode.setValue(rtnList[0]);	// 코드값
			objName.setValue(rtnList[1]);	// 코드명
            objCode.hidVal = rtnList[0];	// 코드값
		} else {
			objCode.setValue("");
			objName.setValue("");
            objCode.hidVal = "";
		}

    } catch (e) {
       console.log(e);
    }
};

  	//-------------------------------------------------------------------------
  	// 조건에 따라 DataSet 가져오기
	//-------------------------------------------------------------------------
	scwin.f_GetDataSet = function(row) {
//console.log("bizClsCd ==>"+ds_merchantcertilist.getCellData(row, "bizClsCd"));
		if (ds_merchantcertilist.getCellData(row, "bizClsCd") == "01"){
			//운송
            gr_merchantcertidtllist.setColumnVisible("wrkDt", false);	
            gr_merchantcertidtllist.setColumnVisible("arrowDdCnt", false);	
            gr_merchantcertidtllist.setColumnVisible("freeday", false);	
            gr_merchantcertidtllist.setColumnVisible("jdgcstmdtAmt", false);

            gr_merchantcertidtllist.setColumnVisible("cntrTypCd", true);
            gr_merchantcertidtllist.setColumnVisible("cntrSizCd", true);
            gr_merchantcertidtllist.setColumnVisible("transDst", true);
            gr_merchantcertidtllist.setColumnVisible("invoiceNo", true);

		} else if (ds_merchantcertilist.getCellData(row, "bizClsCd") == "02"){
			//보관
            gr_merchantcertidtllist.setColumnVisible("wrkDt", true);	
            gr_merchantcertidtllist.setColumnVisible("arrowDdCnt", true);	
            gr_merchantcertidtllist.setColumnVisible("freeday", true);	
            gr_merchantcertidtllist.setColumnVisible("jdgcstmdtAmt", true);

            gr_merchantcertidtllist.setColumnVisible("cntrTypCd", false);	
            gr_merchantcertidtllist.setColumnVisible("cntrSizCd", false);
            gr_merchantcertidtllist.setColumnVisible("transDst", false);
            gr_merchantcertidtllist.setColumnVisible("invoiceNo", false);

		} else if (ds_merchantcertilist.getCellData(row, "bizClsCd") == "03"){
			//하역
            gr_merchantcertidtllist.setColumnVisible("wrkDt", true);	
            gr_merchantcertidtllist.setColumnVisible("arrowDdCnt", true);	
            gr_merchantcertidtllist.setColumnVisible("freeday", true);	
            gr_merchantcertidtllist.setColumnVisible("jdgcstmdtAmt", true);

            gr_merchantcertidtllist.setColumnVisible("cntrTypCd", false);	
            gr_merchantcertidtllist.setColumnVisible("cntrSizCd", false);	
            gr_merchantcertidtllist.setColumnVisible("transDst", false);	
            gr_merchantcertidtllist.setColumnVisible("invoiceNo", false);	
		}	

     	ds_merchantcertidtllist_con.set("certiNo",ds_merchantcertilist.getCellData(row, "certiNo"));

        $c.sbm.execute(sbm_merchantcertidtllist_retrieve);
	};

	//-------------------------------------------------------------------------
	// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
	//-------------------------------------------------------------------------
	scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
		// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
		//if (!cfCanOpenPopup(inObj, pairObj))
		if (!await $c.gus.cfCanOpenPopup(inObj, pairObj))
			return;

		// 짝이 되는 오브젝트의 값 제거
		$c.gus.cfClearPairObj(pairObj);

		// 검색어 세팅
		var pVal = $c.gus.cfGetValue(inObj);

		// inObj가 코드 필드일 경우 팝업
		if (isCode == null || isCode == true)
			scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
		// inObj가 코드명 필드일 경우 팝업
		else
			scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
	};

	//-------------------------------------------------------------------------
	// 조회조건 Clear
	//-------------------------------------------------------------------------
	scwin.f_FieldClear = function() {
		//cfInitObjects(tbl_search,[ed_bilgLodeptCd,ed_bilgLodeptNm,ed_qryConDtFm,ed_qryConDtTo,acb_dcsnClsCd,acb_delYn]);
        $c.gus.cfInitObjects(tbl_search,[ed_bilgLodeptCd,ed_bilgLodeptNm,ed_qryConDtFm,ed_qryConDtTo,acb_dcsnClsCd,acb_delYn]);
	};


	//-------------------------------------------------------------------------
	//엑셀 다운로드
  	//-------------------------------------------------------------------------		
	scwin.f_downExcelSheet = function(vObjGrd){
		var vObjGrd;
		var sheetTitle;

		cfrm = confirm("EXCEL로 다운로드 받으시겠습니까?");
		if(cfrm){
			sheetTitle = "거래명세서 현황 조회";
		    var objGrd = eval(vObjGrd);
		    cfGridToExcel(objGrd, "거래명세서상세", "거래명세서상세.xls", 4+8+16);
		}
	};

  	//-------------------------------------------------------------------------
  	// 발행
	//-------------------------------------------------------------------------
	scwin.f_Print = async function () {

		if(ds_merchantcertidtllist.getRowCount() == 0){
			await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
  		    return;   
		}

		if (! await $c.win.confirm("인쇄하시겠습니까?"))
			return; 

/*         var ozMode = "";
        if (cbx_printCheck.getValue() == "1" && cbx_previewCheck.getValue() == "1") { // 인쇄옵션, 미리보기 둘다 체크된 경우
            ozMode = "preview";
        } else if (cbx_printCheck.getValue() == "1") { // 인쇄옵션만 체크된 경우
            ozMode = "print";
        } else if (cbx_printCheck.getValue() == "1") { // 미리보기만 체크된 경우
            ozMode = "preview";
        } */

        // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
        //var odiParam = new ODIParam("fs_204_02_02p");
        var odiParam = {};
        odiParam.bilgLodeptCd = ed_bilgLodeptCd.getValue();
        odiParam.qryConDtFm = ed_qryConDtFm.getValue();
        odiParam.qryConDtTo = ed_qryConDtTo.getValue();
        odiParam.bilgClntNo = ed_bilgClntNo.getValue();
        odiParam.lineCd = ed_lineCd.getValue();			
        odiParam.vsslCd = ed_vsslCd.getValue();			
        odiParam.portcnt = ed_portcnt.getValue();			
        odiParam.dcsnClsCd = acb_dcsnClsCd.getValue();
        odiParam.modId = ed_modId.getValue();
        if(acb_qryConKnd.getValue() == "품명명"){
            odiParam.qryConCd = ed_qryConCd.getValue();
        } else {
            odiParam.qryConCd = ed_qryConCd.getValue();
        }			
        odiParam.qryConKnd = acb_qryConKnd.getValue();
        odiParam.fmlaPatternCd = acb_fmlaPatternCd.getValue();
        odiParam.qryDtConKnd = acb_qryDtConKnd.getValue();
        odiParam.delYn = acb_delYn.getValue();
        odiParam.certiPatternCd = scwin.certiPatternCd;
        odiParam.fmlaClsCd = scwin.fmlaClsCd;
        odiParam.transCargoClsCd = acb_transCargoClsCd.getValue();
        if (cbx_impExpDomesticClsCd01.getSelectedIndex().length > 0){
            odiParam.impExpDomesticClsCd01 = "I";
        } 
        if (cbx_impExpDomesticClsCd02.getSelectedIndex().length > 0){
            odiParam.impExpDomesticClsCd02 = "O";
        } 
        if (cbx_impExpDomesticClsCd03.getSelectedIndex().length > 0){
            odiParam.impExpDomesticClsCd03 = "D";
        }      		     	
        odiParam.bilgLodeptNm = ed_bilgLodeptNm.getValue();
        odiParam.qryDtConKndNm = acb_qryDtConKnd.getValue();			
        odiParam.ed_qryConDtFm = ed_qryConDtFm.getValue();
        odiParam.ed_qryConDtTo = ed_qryConDtTo.getValue();
        odiParam.fmlaNm = acb_fmlaPatternCd.getValue();
        odiParam.bilgClntNm = ed_bilgClntNm.getValue();
        odiParam.dcsnClsNm = acb_dcsnClsCd.getValue();
        odiParam.transCargoClsNm = acb_transCargoClsCd.getValue();
        odiParam.lineNm = ed_lineCd.getValue();			
        odiParam.vsslNm = ed_vsslCd.getValue();			
        odiParam.portcntNm = ed_portcnt.getValue();			
        //odiParam.delYnNm = acb_delYn.getSelectedIndex();
        odiParam.delYnNm = acb_delYn.getText(true);

        if (cbx_impExpDomesticClsCd01.getSelectedIndex().length > 0){
            odiParam.impExpDomesticClsNm01 = "수입";
        } 
        if (cbx_impExpDomesticClsCd02.getSelectedIndex().length > 0){
            odiParam.impExpDomesticClsNm02 = "수출";
        } 
        if (cbx_impExpDomesticClsCd03.getSelectedIndex().length > 0){
            odiParam.impExpDomesticClsNm03 = "내수";
        }      		     	
        if (cbx_offsetYn.getSelectedIndex().length > 0){
