        } else {
            odiParam.offsetYn = "N";
        }
        if (cbx_upClsCd.getSelectedIndex().length > 0){
            odiParam.upDownClsCd = "UP";
        } else if(cbx_downClsCd.getSelectedIndex().length > 0){
            odiParam.upDownClsCd = "DOWN";
        } else {
            odiParam.upDownClsCd = "NULL";
        }


        let data = {
            odiName  : "fs_204_02_02p",
            reportName: "/ds/fs/fs_204_02_02p.ozr",
            odiParam: odiParam,

            formParam: { 
            },

            viewerParam: {
                    //useprogressbar : true, // 프로그레스바 쓸지 말지
                    //zoom : 90, // 배율 설정
            }
        };

//console.log("레프트 출력~~~");
//console.log(cbx_printCheck.getValue() +" : "+cbx_previewCheck.getValue());

        if (cbx_printCheck.getValue() == "1"){ // 인쇄옵션
            let opts = {
                "type": 'print',
                "printMode": 'view'
            };
            $c.ext.printOzReport(data, opts);
        }else if(cbx_previewCheck.getValue() == "1") { // 미리보기
            let opts = {
                "type": 'viewer',
                "printMode": 'view'
            };
            $c.ext.openOzReport(data, opts);

        }else{
            let opts = {
                filename: '',
                exportMode:'view'
            }

            $c.ext.downloadOzReport(data, opts);
        }

