scwin.sbm_merchantcertilist_retrieve_submitdone = function (e) {
    ds_merchantcertidtllist.removeAll();
    //cfShowTotalRows(totalRows2, 0);
    //tr_merchantcertilist_retrieve.Action = "/ds.fs.bilg.bilgrsltsmgnt.RetrieveMerchantCertiListCMD.do";
    //tr_merchantcertilist_retrieve.Post();

    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    var rowcnt = ds_merchantcertilist.getRowCount();
    tbx_totalRows.setValue(rowcnt);

    if (rowcnt == 0) {
		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	}else{
//console.log("acb_qryDtConKnd.getValue() =="+acb_qryDtConKnd.getValue());
        gr_merchantcertilist.setFocusedCell(0, 1, false);            //gr_merchantcertilist_onrowindexchange 실행됨.
    }
};

